// Worked focus: httpsts-authority-redaction-evidence — Record bounded route, request ID, trusted peer, and redacted target evidence without logging credentials, tokens, personal data, or unbounded query values.
// Evidence: httpsts-worked-http-server-ts-request-authority-proxy-4
// Competency: httpsts-worked-http-server-ts-request-authority-proxy-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_request_authority_proxy_4(host: string, forwardedHost: string, trustedProxy: boolean): { authority: string; allowed: boolean } {
  const authority = trustedProxy && forwardedHost.length > 0 ? forwardedHost : host;
  const normalized = authority.toLowerCase();
  const allowed = normalized === "api.example.test" || normalized === "api.example.test:443";
  return { authority: normalized, allowed };
}

